import React, { useState, useRef, useEffect } from 'react';

function DrawingCanvas({ cameraData, onSave, onBack }) {
  // State giống Python
  const [drawing, setDrawing] = useState(false);
  const [lines, setLines] = useState([]); // Lưu 2 line: axis và coord
  const [polyPoints, setPolyPoints] = useState([]); // Lưu 4 điểm polygon
  const [ix, setIx] = useState(-1);
  const [iy, setIy] = useState(-1);
  const [tempPoint, setTempPoint] = useState(null);

  const canvasRef = useRef(null);
  const imageRef = useRef(null);
  const [imageSize, setImageSize] = useState({ w: 1920, h: 1080 });

  // Hàm tạo UUID
  const generateUUID = () => {
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
      const r = Math.random() * 16 | 0;
      const v = c === 'x' ? r : (r & 0x3 | 0x8);
      return v.toString(16);
    });
  };

  // Hàm làm tròn 3 chữ số
  const roundTo3 = (num) => {
    return Math.round(num * 1000) / 1000;
  };

  // Chuẩn hóa tọa độ
  const normalizeCoordinates = () => {
    const w = imageSize.w;
    const h = imageSize.h;

    // Chuẩn hóa axis - line đầu tiên (màu đen)
    const axis = lines[0] ? [
      roundTo3(lines[0][0] / w),
      roundTo3(lines[0][1] / h),
      roundTo3(lines[0][2] / w),
      roundTo3(lines[0][3] / h)
    ] : [];

    // Chuẩn hóa coord - line thứ hai (mũi tên đỏ)
    const coord = lines[1] ? [
      roundTo3(lines[1][0] / w),
      roundTo3(lines[1][1] / h),
      roundTo3(lines[1][2] / w),
      roundTo3(lines[1][3] / h)
    ] : [];

    return { axis, coord };
  };

  // Tạo preview data theo format yêu cầu
  const generatePreviewData = () => {
    const { axis, coord } = normalizeCoordinates();
    const cam_id = generateUUID();
    const zone_id = generateUUID();

    return {
      list_camera: [
        {
          cam_info: {
            url: cameraData.rtspUrl,
            cam_id: cam_id
          },
          config: {
            direction: [],
            heatmap: {},
            layout: {},
            zone: [{
              ID: zone_id,
              type: 1,
              axis: axis,
              coord: coord,
            }],
            reid: {
              faiss_switch: 0.6,
              faiss_staff_db: 0.8
            }
          }
        }
      ]
    };
  };

  // Xử lý mouse events (giữ nguyên như cũ)
  const handleMouseDown = (e) => {
    if (!canvasRef.current || !imageRef.current) return;

    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;

    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    if (lines.length >= 2) {
      setPolyPoints(prev => [...prev, { x, y }]);

      const ctx = canvas.getContext('2d');
      ctx.beginPath();
      ctx.arc(x, y, 5, 0, 2 * Math.PI);
      ctx.fillStyle = '#ff0000';
      ctx.fill();
      ctx.strokeStyle = '#ffffff';
      ctx.lineWidth = 2;
      ctx.stroke();

      if (polyPoints.length > 0) {
        const lastPoint = polyPoints[polyPoints.length - 1];
        ctx.beginPath();
        ctx.moveTo(lastPoint.x, lastPoint.y);
        ctx.lineTo(x, y);
        ctx.strokeStyle = '#ff0000';
        ctx.lineWidth = 2;
        ctx.stroke();
      }
    } else {
      setDrawing(true);
      setIx(x);
      setIy(y);
    }
  };

  const handleMouseMove = (e) => {
    if (!drawing || !canvasRef.current || lines.length >= 2) return;

    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;

    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    setTempPoint({ x, y });

    const ctx = canvas.getContext('2d');
    redrawAll();

    ctx.beginPath();
    ctx.moveTo(ix, iy);
    ctx.lineTo(x, y);

    if (lines.length === 0) {
      ctx.strokeStyle = '#000000';
      ctx.lineWidth = 2;
      ctx.stroke();
    } else if (lines.length === 1) {
      drawArrow(ctx, ix, iy, x, y, '#ff0000', 2);
    }
  };

  const handleMouseUp = (e) => {
    if (!drawing || !canvasRef.current || lines.length >= 2) return;

    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;

    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    const newLine = [ix, iy, x, y];

    setLines([...lines, newLine]);
    setDrawing(false);
    setTempPoint(null);

    const ctx = canvas.getContext('2d');

    if (lines.length === 0) {
      ctx.beginPath();
      ctx.moveTo(ix, iy);
      ctx.lineTo(x, y);
      ctx.strokeStyle = '#000000';
      ctx.lineWidth = 3;
      ctx.stroke();
      console.log("✅ Đã vẽ Axis");
    } else if (lines.length === 1) {
      drawArrow(ctx, ix, iy, x, y, '#ff0000', 4);
      console.log("✅ Đã vẽ Coord");
    }
  };

  const drawArrow = (ctx, fromX, fromY, toX, toY, color, width) => {
    const headLength = 20;
    const angle = Math.atan2(toY - fromY, toX - fromX);

    ctx.beginPath();
    ctx.moveTo(fromX, fromY);
    ctx.lineTo(toX, toY);
    ctx.strokeStyle = color;
    ctx.lineWidth = width;
    ctx.stroke();

    ctx.beginPath();
    ctx.moveTo(toX, toY);
    ctx.lineTo(
      toX - headLength * Math.cos(angle - Math.PI / 6),
      toY - headLength * Math.sin(angle - Math.PI / 6)
    );
    ctx.lineTo(
      toX - headLength * Math.cos(angle + Math.PI / 6),
      toY - headLength * Math.sin(angle + Math.PI / 6)
    );
    ctx.closePath();
    ctx.fillStyle = color;
    ctx.fill();
  };

  const redrawAll = () => {
    if (!canvasRef.current || !imageRef.current) return;

    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    lines.forEach((line, index) => {
      const [x1, y1, x2, y2] = line;

      if (index === 0) {
        ctx.beginPath();
        ctx.moveTo(x1, y1);
        ctx.lineTo(x2, y2);
        ctx.strokeStyle = '#000000';
        ctx.lineWidth = 3;
        ctx.stroke();
      } else if (index === 1) {
        drawArrow(ctx, x1, y1, x2, y2, '#ff0000', 4);
      }
    });

    if (polyPoints.length > 0) {
      ctx.strokeStyle = '#ff0000';
      ctx.lineWidth = 2;
      ctx.fillStyle = 'rgba(255, 0, 0, 0.1)';

      ctx.beginPath();
      ctx.moveTo(polyPoints[0].x, polyPoints[0].y);

      for (let i = 1; i < polyPoints.length; i++) {
        ctx.lineTo(polyPoints[i].x, polyPoints[i].y);
      }

      if (polyPoints.length === 4) {
        ctx.lineTo(polyPoints[0].x, polyPoints[0].y);
        ctx.stroke();
        ctx.fill();
      } else {
        ctx.stroke();
      }

      polyPoints.forEach((point, index) => {
        ctx.beginPath();
        ctx.arc(point.x, point.y, 5, 0, 2 * Math.PI);
        ctx.fillStyle = '#ff0000';
        ctx.fill();
        ctx.strokeStyle = '#ffffff';
        ctx.lineWidth = 2;
        ctx.stroke();

        ctx.fillStyle = '#ffffff';
        ctx.font = 'bold 12px Arial';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText(index + 1, point.x, point.y);
      });
    }
  };

  const handleSave = () => {
    if (lines.length < 2) {
      alert('Cần vẽ đủ Axis và Coord');
      return;
    }

    if (polyPoints.length < 4) {
      alert('Cần click 4 điểm để tạo Zone Polygon');
      return;
    }

    const { axis, coord } = normalizeCoordinates();
    const zone_id = generateUUID();

    const config = {
      zone: [{
        ID: zone_id,
        type: 1,
        axis: axis,
        coord: coord
      }],
      reid: {
        faiss_switch: 0.6,
        faiss_staff_db: 0.8
      }
    };

    onSave(config);
  };

  const handleReset = () => {
    setLines([]);
    setPolyPoints([]);
    setDrawing(false);
    setIx(-1);
    setIy(-1);
    setTempPoint(null);

    if (canvasRef.current) {
      const ctx = canvasRef.current.getContext('2d');
      ctx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
    }
  };

  useEffect(() => {
    redrawAll();
  }, [lines, polyPoints]);

  useEffect(() => {
    if (imageRef.current) {
      const img = imageRef.current;
      setImageSize({ w: img.naturalWidth, h: img.naturalHeight });
    }
  }, [cameraData.imagePreview]);

  const previewData = generatePreviewData();
  const hasFullData = lines.length === 2 && polyPoints.length >= 4;

  return (
    <div className="drawing-canvas">
      <div className="instructions">
        <h4>📝 Hướng dẫn vẽ:</h4>
        <p>1. Kéo thả chuột vẽ Axis (line đen)</p>
        <p>2. Kéo thả chuột vẽ Coord (mũi tên đỏ)</p>
        <p>3. Click 4 điểm để tạo Zone Polygon (màu đỏ)</p>
      </div>

      <div className="canvas-container">
        <img 
          ref={imageRef}
          src={cameraData.imagePreview} 
          alt="Camera"
          onLoad={() => {
            if (canvasRef.current && imageRef.current) {
              canvasRef.current.width = imageRef.current.naturalWidth;
              canvasRef.current.height = imageRef.current.naturalHeight;
              redrawAll();
            }
          }}
        />
        <canvas
          ref={canvasRef}
          onMouseDown={handleMouseDown}
          onMouseMove={handleMouseMove}
          onMouseUp={handleMouseUp}
          onMouseLeave={() => setDrawing(false)}
        />
      </div>

      <div className="status-panel">
        <div className="status-item">
          <span className="status-label">Axis:</span>
          <span className={`status-value ${lines.length >= 1 ? 'completed' : 'pending'}`}>
            {lines.length >= 1 ? '✓ Đã vẽ' : '⏳ Chưa vẽ'}
          </span>
        </div>
        <div className="status-item">
          <span className="status-label">Coord:</span>
          <span className={`status-value ${lines.length >= 2 ? 'completed' : 'pending'}`}>
            {lines.length >= 2 ? '✓ Đã vẽ' : '⏳ Chưa vẽ'}
          </span>
        </div>
        <div className="status-item">
          <span className="status-label">Polygon:</span>
          <span className={`status-value ${polyPoints.length >= 4 ? 'completed' : 'pending'}`}>
            {polyPoints.length}/4 điểm
          </span>
        </div>
      </div>

      {/* Preview theo format yêu cầu */}
      {hasFullData && (
        <div className="preview-section">
          <div className="preview-header">
            <h4>📋 Preview kết quả:</h4>
            <button 
              className="btn-copy"
              onClick={() => {
                navigator.clipboard.writeText(JSON.stringify(previewData, null, 2));
                alert('Đã copy vào clipboard!');
              }}
            >
              📋 Copy
            </button>
          </div>

          <pre className="json-preview">
            {JSON.stringify(previewData, null, 2)}
          </pre>

          {/* Hiển thị chi tiết tọa độ */}
          <div className="coord-details">
            <h5>📐 Chi tiết tọa độ:</h5>
            <div className="coord-grid">
              <div className="coord-row">
                <span className="coord-label">Axis:</span>
                <span className="coord-value">
                  [{previewData.list_camera[0].config.zone[0].axis.map(v => v.toFixed(3)).join(', ')}]
                </span>
              </div>
              <div className="coord-row">
                <span className="coord-label">Coord:</span>
                <span className="coord-value">
                  [{previewData.list_camera[0].config.zone[0].coord.map(v => v.toFixed(3)).join(', ')}]
                </span>
              </div>
            </div>
          </div>

          {/* Hiển thị thông tin camera */}
          <div className="camera-info-preview">
            <h5>📹 Thông tin camera:</h5>
            <p><strong>URL:</strong> {previewData.list_camera[0].cam_info.url}</p>
            <p><strong>Camera ID:</strong> {previewData.list_camera[0].cam_info.cam_id}</p>
            <p><strong>Zone ID:</strong> {previewData.list_camera[0].config.zone[0].ID}</p>
          </div>
        </div>
      )}

      <div className="action-buttons">
        <button onClick={onBack} className="btn-back">
          ← Quay lại
        </button>
        <button onClick={handleReset} className="btn-reset">
          🔄 Reset
        </button>
        <button 
          onClick={handleSave} 
          className="btn-save"
          disabled={!hasFullData}
        >
          {hasFullData ? '💾 Lưu camera' : 'Vẽ đủ 3 bước'}
        </button>
      </div>

      <style jsx>{`
